    seoRegion: "<!-- BUILD:SEO -->\n<link rel=\"canonical\" href=\"https://www.davnoot.com/services/email\" />\n<meta name=\"robots\" content=\"index, follow\" />\n<meta name=\"keywords\" content=\"email marketing agency, email marketing automation, lifecycle marketing, email flows, list segmentation, lead nurturing, retention marketing, Klaviyo agency\" />\n<link rel=\"icon\" type=\"image/png\" href=\"/images/davnoot-logo.png\" />\n<link rel=\"apple-touch-icon\" href=\"/images/davnoot-logo.png\" />\n<meta property=\"og:type\" content=\"website\" />\n<meta property=\"og:site_name\" content=\"Davnoot\" />\n<meta property=\"og:title\" content=\"Email Marketing Agency | Email Marketing Automation | Davnoot\" />\n<meta property=\"og:description\" content=\"Email marketing and automation that nurtures leads, recovers revenue, and builds loyalty. Flows, segmentation, and lifecycle strategy built to convert.\" />\n<meta property=\"og:url\" content=\"https://www.davnoot.com/services/email\" />\n<meta property=\"og:image\" content=\"https://www.davnoot.com/images/davnoot-logo.png\" />\n<meta name=\"twitter:card\" content=\"summary_large_image\" />\n<meta name=\"twitter:title\" content=\"Email Marketing Agency | Email Marketing Automation | Davnoot\" />\n<meta name=\"twitter:description\" content=\"Email marketing and automation that nurtures leads, recovers revenue, and builds loyalty. Flows, segmentation, and lifecycle strategy built to convert.\" />\n<meta name=\"twitter:image\" content=\"https://www.davnoot.com/images/davnoot-logo.png\" />\n<script type=\"application/ld+json\">\n{\n  \"@context\": \"https://schema.org\",\n  \"@graph\": [\n    {\n      \"@type\": \"Organization\",\n      \"@id\": \"https://www.davnoot.com/#organization\",\n      \"name\": \"Davnoot\",\n      \"url\": \"https://www.davnoot.com/\",\n      \"logo\": \"https://www.davnoot.com/images/davnoot-logo.png\",\n      \"image\": \"https://www.davnoot.com/images/davnoot-logo.png\",\n      \"description\": \"Davnoot is an independent growth agency. Six disciplines: SEO, paid social, email, AI search, ChatGPT ads, and custom software. Engineered into one revenue engine.\",\n      \"email\": \"info@davnoot.com\",\n      \"telephone\": \"+1-438-223-7131\",\n      \"foundingDate\": \"2025\",\n      \"address\": {\n        \"@type\": \"PostalAddress\",\n        \"addressLocality\": \"Montreal\",\n        \"addressRegion\": \"QC\",\n        \"addressCountry\": \"CA\"\n      },\n      \"areaServed\": \"Worldwide\"\n    },\n    {\n      \"@type\": \"Service\",\n      \"name\": \"Email Marketing Agency | Email Marketing Automation\",\n      \"serviceType\": \"Email Marketing\",\n      \"description\": \"Email marketing and automation that nurtures leads, recovers revenue, and builds loyalty. Flows, segmentation, and lifecycle strategy built to convert.\",\n      \"url\": \"https://www.davnoot.com/services/email\",\n      \"provider\": {\n        \"@id\": \"https://www.davnoot.com/#organization\"\n      },\n      \"areaServed\": \"Worldwide\"\n    },\n    {\n      \"@type\": \"FAQPage\",\n      \"@id\": \"https://www.davnoot.com/services/email#faq\",\n      \"mainEntity\": [\n        {\n          \"@type\": \"Question\",\n          \"name\": \"How big does my list need to be?\",\n          \"acceptedAnswer\": {\n            \"@type\": \"Answer\",\n            \"text\": \"10,000 active subscribers is the practical floor for meaningful revenue impact. Below that, list growth becomes the priority before optimization, and we'll tell you so honestly.\"\n          }\n        },\n        {\n          \"@type\": \"Question\",\n          \"name\": \"What ESPs do you work with?\",\n          \"acceptedAnswer\": {\n            \"@type\": \"Answer\",\n            \"text\": \"Klaviyo for ecommerce, Customer.io for SaaS and product-led businesses, Mailchimp only when there's existing setup we shouldn't disrupt. We have strong opinions about platforms, and good reasons for them.\"\n          }\n        },\n        {\n          \"@type\": \"Question\",\n          \"name\": \"How often will you actually send?\",\n          \"acceptedAnswer\": {\n            \"@type\": \"Answer\",\n            \"text\": \"Frequency is segment-specific. Engaged subscribers get 2–3 emails per week; less engaged segments get less, treated more carefully. We optimize for revenue per subscriber, not send volume.\"\n          }\n        },\n        {\n          \"@type\": \"Question\",\n          \"name\": \"What if my brand isn't a fit for \\\"salesy\\\" emails?\",\n          \"acceptedAnswer\": {\n            \"@type\": \"Answer\",\n            \"text\": \"Good, neither are we. The best email programs feel like a great editorial newsletter that occasionally sells something, not a discount factory.\"\n          }\n        },\n        {\n          \"@type\": \"Question\",\n          \"name\": \"How do you handle deliverability if it's bad?\",\n          \"acceptedAnswer\": {\n            \"@type\": \"Answer\",\n            \"text\": \"First 30 days are warming, list cleaning, and authentication setup (SPF, DKIM, DMARC, BIMI). We protect sender reputation aggressively. It's the foundation that lets every other tactic work.\"\n          }\n        }\n      ]\n    }\n  ]\n}\n</script>\n<!-- /BUILD:SEO -->",
